#!/usr/bin/env bash
# Generated by CodeRabbitReviewer (EVA-3). CLI progress + findings stream
# live and are teed into FINDINGS.md. Secrets are sourced from outside
# the repo and never appear in this file.
set -eu -o pipefail
# Self-locating: this committed artifact embeds no machine paths.
tool_dir="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
trap 'status=$?; rm -rf '/tmp/evie-coderabbit-0733Nh'; if [ "$status" -ne 0 ] && [ ! -f "$tool_dir/.failed" ] && [ ! -f "$tool_dir/.done" ]; then echo "reviewer script exited $status without reporting" > "$tool_dir/.failed"; fi' EXIT
# Ephemeral secrets env in a temp dir OUTSIDE the repo, deleted on exit \u2014
# this absolute path is intentional and NON-REPLAYABLE once the wave ends.
source '/tmp/evie-coderabbit-0733Nh/env.sh' || { echo "secrets env missing" > "$tool_dir/.failed"; exit 1; }
repo_root="$(git -C "$tool_dir" rev-parse --show-toplevel 2>/dev/null)" || {
  echo "cannot resolve the checkout: $tool_dir is not inside the reviewed repo" > "$tool_dir/.failed"; exit 1;
}
cd "$repo_root" || { echo "checkout missing: $repo_root" > "$tool_dir/.failed"; exit 1; }
cr_base='main'
echo "\u2500\u2500 coderabbit reviewer: $(git branch --show-current) vs $cr_base \u2500\u2500"
printf '# CodeRabbit findings\n\n' > "$tool_dir/FINDINGS.md"
cr_status=0
# --api-key comes from the sourced env, never from this committed script.
coderabbit review --api-key "$CODERABBIT_API_KEY" '--plain' '--type' 'committed' '--base' 'main' 2>&1 | tee -a "$tool_dir/FINDINGS.md" || cr_status=$?
if [ "$cr_status" -ne 0 ]; then
  echo "coderabbit review exited $cr_status" > "$tool_dir/.failed"
  echo "=== CODERABBIT REVIEWER FAILED (exit $cr_status) ==="
  exit "$cr_status"
fi
# AI-prompt capture (EVA-31): --show-prompts is a separate NO-REVIEW mode
# printing the prompts the CLI saved with the review above, so it gets its
# own invocation. Auxiliary aid, never a veto: a nonzero exit, an empty
# dump, or expiry of the time bound is recorded loudly in PROMPTS.md and
# .prompts-failed (a wave note), while the completed review stands.
# Ordered BEFORE the completion marker so the wave cannot observe
# completion while capture is still writing; the perl alarm+exec bound
# (portable \u2014 GNU timeout is not on stock macOS; alarm survives exec) is
# what keeps a hung capture from stall-vetoing the review it rode behind.
echo
echo "\u2500\u2500 capturing AI prompts into PROMPTS.md (auxiliary; review already complete) \u2500\u2500"
{
  echo "# CodeRabbit AI prompts"
  echo
  echo "Per-finding AI prompts saved by the CLI with the review in"
  echo "FINDINGS.md, captured by a second \`coderabbit review --show-prompts\`"
  echo "invocation (EVA-31). RECORDED as reconciliation aid \u2014 understanding"
  echo "why CodeRabbit flagged a finding, tuning \`--config\` instructions \u2014"
  echo "and NEVER executed directly (the autofix rule)."
  echo
} > "$tool_dir/PROMPTS.md"
prompts_header_bytes="$(wc -c < "$tool_dir/PROMPTS.md")"
prompts_status=0
prompts_raw="$tool_dir/.prompts-raw"
# Bounded, and deliberately NOT a pipeline: SIGALRM kills only the
# exec'd CLI, and a CLI descendant inheriting stdout would hold a pipe's
# write end open \u2014 tee would wait for EOF past the bound, reopening the
# stall-veto window (results-002 cc/codex finding). A file redirect
# keeps bash waiting on the bounded process alone; the dump is echoed to
# the pane right after (print-only mode \u2014 the live-tee requirement
# guards the REVIEW stream above, which still tees).
perl -e 'alarm shift; exec @ARGV' 300 coderabbit review --api-key "$CODERABBIT_API_KEY" --show-prompts --plain > "$prompts_raw" 2>&1 || prompts_status=$?
tee -a "$tool_dir/PROMPTS.md" < "$prompts_raw"
rm -f "$prompts_raw"
prompts_body_bytes=$(($(wc -c < "$tool_dir/PROMPTS.md") - prompts_header_bytes))
prompts_body_chars="$(tail -c +$((prompts_header_bytes + 1)) "$tool_dir/PROMPTS.md" | tr -d '[:space:]' | wc -c | tr -d ' ')"
if [ "$prompts_status" -ne 0 ] || [ "$prompts_body_chars" -eq 0 ]; then
  if [ "$prompts_status" -eq 142 ]; then
    prompts_note="AI-prompt capture timed out after 300s (SIGALRM/exit 142) \u2014 the completed review is unaffected"
  else
    prompts_note="AI-prompt capture failed (show-prompts exit $prompts_status, $prompts_body_chars non-whitespace chars in $prompts_body_bytes bytes of output) \u2014 the completed review is unaffected"
  fi
  printf '%s\n' "$prompts_note" > "$tool_dir/.prompts-failed"
  printf '\n**CAPTURE FAILED** \u2014 %s\n' "$prompts_note" >> "$tool_dir/PROMPTS.md"
  echo "capture note: $prompts_note"
else
  echo "captured $prompts_body_bytes bytes of prompts"
fi
printf '\n%s\n' 'REVIEW COMPLETE' | tee -a "$tool_dir/FINDINGS.md"
touch "$tool_dir/.done"
echo "=== CODERABBIT REVIEWER DONE ==="
